args.cypher:
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
MATCH (aas)-[:MANAGES_ASSET]->(asset:Asset)
WHERE EXISTS { MATCH (sm)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/Submodel/1/0/Location'}) }
   OR EXISTS { MATCH (sm)-[:HAS_SUPPLEMENTAL_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/Submodel/1/0/Location'}) }
RETURN aas.id AS aas_id, aas.idShort AS aas_idShort, asset.globalAssetId, asset.assetKind
